use std::fmt;

trait Measurable {
    fn calculate_area(&self) -> f64;
}

struct Circle { 
    radius: f64,
}

impl Measurable for Circle {
    fn calculate_area(&self) -> f64 {
        std::f64::consts::PI * self.radius * self.radius
    }
}

struct Square { 
    side: f64,
}

impl Measurable for Square {
    fn calculate_area(&self) -> f64 {
        self.side * self.side
    }
}

fn process_shapes(shapes: Vec<Box<dyn Measurable>>) -> f64 {
    let mut total_area = 0.0;
    for shape in shapes {
        total_area += shape.calculate_area();
    }
    total_area
}

fn main() {
    let circle = Circle { radius: 5.0 };
    let square = Square { side: 4.0 };

    let shapes_to_process: Vec<Box<dyn Measurable>> = vec![Box::new(circle), Box::new(square)];

    let total_area = process_shapes(shapes_to_process);
    println!("The combined area is: {}", total_area);
}

use std::error::Error;

trait Processable {
    fn execute(&self) -> Result<(), Box<dyn Error>>; 
}

struct UserA; 
impl Processable for UserA {
    fn execute(&self) -> Result<(), Box<dyn Error>> {
        println!("Processing User A successfully.");
        Ok(())
    }
}

struct UserB;
impl Processable for UserB {
    fn execute(&self) -> Result<(), Box<dyn Error>> {
        println!("Processing User B successfully.");
        Ok(()) 
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let items: Vec<Box<dyn Processable>> = vec![ 
        Box::new(UserA),
        Box::new(UserB)
    ];

    for item in items {
