use std::fmt;

trait Actionable {
    fn perform_action(&self) -> String;
}

struct Dog { 
    name: String,
    energy: i32,
}

impl Actionable for Dog {
    fn perform_action(&self) -> String {
        format!("The dog {} barks loudly and uses {} energy.", self.name, 5)
    }
}

struct Book { 
    title: String,
    pages: u32,
}

impl Actionable for Book {
    fn perform_action(&self) -> String {
        format!("The book {} is opened and read, requiring no energy.", self.title)
    }
}

struct User { 
    username: String,
    is_active: bool,
}

impl Actionable for User {
    fn perform_action(&self) -> String {
        if self.is_active {
            format!("The user {} logs in successfully.", self.username)
        } else {
            String::from("The user account is locked and cannot act.")
        }
    }
}

fn main() {
    let buddy = Dog { name: String::from("Buddy"), energy: 10 };
    let novel = Book { title: String::from("Dune") , pages: 896 };
    let guest = User { username: String::from("Visitor"), is_active: true };

    println!("n--- Action Log ---n");
    println!("{}n", buddy.perform_action());
    println!("{}n", novel.perform_action());
    println!("{}n", guest.perform_action());
}

use std::fmt;

trait Cleanable {
    fn clean(&self) -> String;
}

struct UserRecord { name: String, data: Vec<i32> }
impl Cleanable for UserRecord {
    fn clean(&self) -> String {
        format!("User {} cleaned. Data sum: {}", self.name, self.data.iter().sum::<i32>())
    }
}

struct SensorReading { id: u32, value: f64 }
impl Cleanable for SensorReading {
    fn clean(&self) -> String {
        format!("Sensor {} reading processed. Value adjusted: {}", self.id, self.value * 1.05)
    }
}

fn process_items<T: Cleanable>(item: &T) -> String {
    item.clean()
}

fn main() {
    let user = UserRecord { name: String::from("Alice"), data: vec![10, 20, 30] };
    let sensor = SensorReading { id: 42, value: 5.0 };

    println!("Result 1: {}", process_items(&user));
    println!("Result 2: {}", process_items(&sensor));
}

use std::error::Error;

trait Worker {
    fn process(&self) -> Result<String, Box<dyn Error>>;
}

struct FastWorker;

impl Worker for FastWorker {
    fn process(&self) -> Result<String, Box<dyn Error>> {
        Ok("Processed quickly".to_string())
    }
}

struct SafeWorker;

impl Worker for SafeWorker {
    fn process(&self) -> Result<String, Box<dyn Error>> {
        Ok("Processed safely".to_string())
    }
}

fn execute_task<T: Worker>(worker: &T) -> Result<String, Box<dyn Error>> {
    worker.process()
}

fn main() -> Result<(), Box<dyn Error>> {
    let fast = FastWorker;
    let safe = SafeWorker;

    let result1 = execute_task(&fast);
    println!("Result 1: {}", result1?);

    let result2 = execute_task(&safe);
    println!("Result 2: {}", result2?);

    Ok(())
}
